#include <bits/stdc++.h>
using namespace std;

// Euclidean GCD — O(log min(a,b))
long long gcd(long long a, long long b) {
    return b == 0 ? a : gcd(b, a % b);
}

// LCM — divide before multiply to avoid overflow
long long lcm(long long a, long long b) {
    return a / gcd(a, b) * b;
}

// Extended Euclidean: finds x, y such that a*x + b*y = gcd(a,b)
// Returns gcd(a, b). x and y are set by reference.
long long extgcd(long long a, long long b, long long &x, long long &y) {
    if (b == 0) { x = 1; y = 0; return a; }
    long long x1, y1;
    long long g = extgcd(b, a % b, x1, y1);
    x = y1;
    y = x1 - (a / b) * y1;
    return g;
}

int main() {
    long long a = 48, b = 18;
    cout << "gcd(48,18) = " << gcd(a, b) << "\n"; // 6
    cout << "lcm(48,18) = " << lcm(a, b) << "\n"; // 144

    long long x, y;
    long long g = extgcd(a, b, x, y);
    // 48*x + 18*y = 6
    cout << "48*" << x << " + 18*" << y << " = " << g << "\n";

    // C++17 built-in (works on GCC on Codeforces)
    cout << "__gcd: " << __gcd(48LL, 18LL) << "\n";
    // C++17 std::gcd from <numeric>
    cout << "std::gcd: " << gcd(48LL, 18LL) << "\n";

    return 0;
}

#include <bits/stdc++.h>
using namespace std;

// O(sqrt(n)) primality test
bool isPrime(long long n) {
    if (n < 2) return false;
    if (n == 2) return true;
    if (n % 2 == 0) return false;
    for (long long i = 3; i * i <= n; i += 2)
        if (n % i == 0) return false;
    return true;
}

// O(sqrt(n)) prime factorization
// Returns map: prime -> exponent, e.g. 360 -> {2:3, 3:2, 5:1}
map<long long, int> factorize(long long n) {
    map<long long, int> factors;
    for (long long p = 2; p * p <= n; p++) {
        while (n % p == 0) {
            factors[p]++;
            n /= p;
        }
    }
    if (n > 1) factors[n]++; // remaining large prime factor
    return factors;
}

// Count number of divisors from factorization
// If n = p1^a1 * p2^a2 * ..., divisors = (a1+1)*(a2+1)*...
long long countDivisors(long long n) {
    auto f = factorize(n);
    long long cnt = 1;
    for (auto &[p, e] : f) cnt *= (e + 1);
    return cnt;
}

int main() {
    cout << isPrime(97) << "\n";  // 1 (true)
    cout << isPrime(100) << "\n"; // 0 (false)

    auto f = factorize(360);
    for (auto &[p, e] : f)
        cout << p << "^" << e << " "; // 2^3 3^2 5^1
    cout << "\n";

    cout << "Divisors of 360: " << countDivisors(360) << "\n"; // 24
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

const int MAXN = 1e7 + 5;
vector<bool> isp(MAXN, true);
vector<int> primes;

// Classic sieve — O(N log log N)
void sieve(int n) {
    isp[0] = isp[1] = false;
    for (int i = 2; i <= n; i++) {
        if (isp[i]) {
            primes.push_back(i);
            // start at i*i: smaller multiples already marked
            for (long long j = (long long)i * i; j <= n; j += i)
                isp[j] = false;
        }
    }
}

// Linear Sieve — O(N) strict, also builds SPF (smallest prime factor)
// SPF lets us factorize any number <= N in O(log N)
const int MAXL = 1e6 + 5;
int spf[MAXL]; // spf[i] = smallest prime factor of i
vector<int> lp; // list of primes

void linearSieve(int n) {
    iota(spf, spf + n + 1, 0); // spf[i] = i initially
    for (int i = 2; i <= n; i++) {
        if (spf[i] == i) lp.push_back(i); // i is prime
        for (int p : lp) {
            if (p > spf[i] || (long long)i * p > n) break;
            spf[i * p] = p;
        }
    }
}

// O(log N) factorization using SPF
map<int,int> fastFactor(int n) {
    map<int,int> f;
    while (n > 1) { f[spf[n]]++; n /= spf[n]; }
    return f;
}

int main() {
    sieve(100);
    cout << "Primes up to 100: ";
    for (int p : primes) cout << p << " ";
    cout << "\n";
    cout << "Total: " << primes.size() << "\n"; // 25

    linearSieve(20);
    auto f = fastFactor(18); // 18 = 2^1 * 3^2
    for (auto &[p,e] : f) cout << p << "^" << e << " ";
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

vector<long long> segSieve(long long L, long long R) {
    // Step 1: classic sieve up to sqrt(R)
    long long sqr = (long long)sqrt((double)R) + 1;
    vector<bool> isp(sqr + 1, true);
    isp[0] = isp[1] = false;
    vector<long long> smallP;
    for (long long i = 2; i <= sqr; i++) {
        if (isp[i]) {
            smallP.push_back(i);
            for (long long j = i * i; j <= sqr; j += i)
                isp[j] = false;
        }
    }

    // Step 2: mark composites in segment [L, R]
    long long sz = R - L + 1;
    vector<bool> seg(sz, true);
    if (L == 1) seg[0] = false; // 1 is not prime

    for (long long p : smallP) {
        // first multiple of p >= L
        long long start = max(p * p, (L + p - 1) / p * p);
        for (long long j = start; j <= R; j += p)
            seg[j - L] = false;
    }

    vector<long long> result;
    for (long long i = 0; i < sz; i++)
        if (seg[i]) result.push_back(L + i);
    return result;
}

int main() {
    // Find all primes between 10^9 and 10^9 + 100
    auto primes = segSieve(1000000000LL, 1000000100LL);
    for (long long p : primes) cout << p << " ";
    // 1000000007 1000000009 ...
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

const long long MOD = 1e9 + 7;

// Fast exponentiation (binary exponentiation) — O(log exp)
long long power(long long base, long long exp, long long mod) {
    long long result = 1;
    base %= mod;
    while (exp > 0) {
        if (exp & 1) result = result * base % mod;
        base = base * base % mod;
        exp >>= 1;
    }
    return result;
}

// Modular inverse using Fermat's Little Theorem
// Only valid when mod is PRIME
long long modinv(long long a, long long mod = MOD) {
    return power(a, mod - 2, mod);
}

// Precompute factorials and inverse factorials for C(n,r) mod p
const int MAXN = 2e6 + 5;
long long fact[MAXN], inv_fact[MAXN];

void precompute() {
    fact[0] = 1;
    for (int i = 1; i < MAXN; i++)
        fact[i] = fact[i-1] * i % MOD;
    inv_fact[MAXN-1] = modinv(fact[MAXN-1]);
    for (int i = MAXN-2; i >= 0; i--)
        inv_fact[i] = inv_fact[i+1] * (i+1) % MOD;
}

// Binomial coefficient C(n, r) mod MOD in O(1)
long long C(int n, int r) {
    if (r < 0 || r > n) return 0;
    return fact[n] % MOD * inv_fact[r] % MOD * inv_fact[n-r] % MOD;
}

int main() {
    precompute();

    // Arithmetic examples
    long long a = 1e9, b = 1e9;
    cout << (a + b) % MOD << "\n";         // 999999993
    cout << ((a - b) % MOD + MOD) % MOD << "\n"; // 0 (safe subtraction)
    cout << a % MOD * (b % MOD) % MOD << "\n";   // product

    // Modular inverse: divide by 3 mod p
    cout << modinv(3) << "\n"; // 333333336

    // C(10, 3) = 120
    cout << "C(10,3) = " << C(10, 3) << "\n";
    // C(1000000, 500000) mod 1e9+7
    cout << "C(1000000,500000) = " << C(1000000, 500000) << "\n";

    return 0;
}

#include <bits/stdc++.h>
using namespace std;

typedef long long ll;
typedef pair<ll,ll> pll;

ll extgcd(ll a, ll b, ll &x, ll &y) {
    if (!b) { x = 1; y = 0; return a; }
    ll x1, y1;
    ll g = extgcd(b, a%b, x1, y1);
    x = y1; y = x1 - a/b*y1;
    return g;
}

// Combine: x ≡ r1 (mod m1)  AND  x ≡ r2 (mod m2)
// Returns {r, m} such that x ≡ r (mod m), or {-1,-1} if no solution
pll crt(ll r1, ll m1, ll r2, ll m2) {
    ll x, y;
    ll g = extgcd(m1, m2, x, y);
    if ((r2 - r1) % g != 0) return {-1, -1}; // no solution
    ll lcm = m1 / g * m2;
    ll ans = (r1 + m1 * ((r2 - r1) / g % (m2/g) * x % (m2/g))) % lcm;
    if (ans < 0) ans += lcm;
    return {ans, lcm};
}

int main() {
    // x ≡ 2 (mod 3), x ≡ 3 (mod 5)
    // Solution: x ≡ 8 (mod 15)
    auto [r, m] = crt(2, 3, 3, 5);
    cout << "x ≡ " << r << " (mod " << m << ")\n"; // x ≡ 8 (mod 15)

    // Verify: 8 % 3 = 2 ✓, 8 % 5 = 3 ✓
    cout << r % 3 << " " << r % 5 << "\n"; // 2 3
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

// O(sqrt(n)) totient of a single n
long long phi(long long n) {
    long long result = n;
    for (long long p = 2; p * p <= n; p++) {
        if (n % p == 0) {
            while (n % p == 0) n /= p;
            result -= result / p; // result *= (1 - 1/p)
        }
    }
    if (n > 1) result -= result / n; // remaining prime factor
    return result;
}

// Sieve for phi of all numbers up to N — O(N log log N)
void phiSieve(int n, vector<int> &phi_arr) {
    phi_arr.resize(n + 1);
    iota(phi_arr.begin(), phi_arr.end(), 0); // phi[i] = i initially
    for (int i = 2; i <= n; i++) {
        if (phi_arr[i] == i) { // i is prime
            for (int j = i; j <= n; j += i)
                phi_arr[j] -= phi_arr[j] / i;
        }
    }
}

int main() {
    cout << "phi(12) = " << phi(12) << "\n";  // 4: {1,5,7,11}
    cout << "phi(13) = " << phi(13) << "\n";  // 12 (13 is prime)
    cout << "phi(36) = " << phi(36) << "\n";  // 12

    vector<int> ph;
    phiSieve(10, ph);
    for (int i = 1; i <= 10; i++)
        cout << "phi(" << i << ")=" << ph[i] << " ";
    // phi(1)=1 phi(2)=1 phi(3)=2 phi(4)=2 phi(5)=4 ...
    return 0;
}

