#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n;
    cin >> n;

    // cnt[i] = number of divisors of i
    vector<long long> cnt(n + 1, 0);

    // For each divisor k, mark all its multiples
    for (int k = 1; k <= n; k++)
        for (int mult = k; mult <= n; mult += k)
            cnt[mult]++;

    long long ans = 0;
    for (int i = 1; i <= n; i++) ans += cnt[i];

    cout << ans << "\n";
    return 0;
}

// Alternative: mathematical formula approach
// sum_{i=1}^{N} d(i) = sum_{k=1}^{N} floor(N/k)
// This avoids the array entirely:
void mathVersion(int n) {
    long long ans = 0;
    for (int k = 1; k <= n; k++)
        ans += n / k;
    cout << ans << "\n";
}

