#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n, K;
    cin >> n >> K;

    const int MAXV = 1e6 + 1;
    vector<int> freq(MAXV, 0);
    for (int i = 0; i < n; i++) {
        int x; cin >> x;
        freq[x]++;
    }

    // cnt[d] = number of elements divisible by d
    vector<long long> cnt(MAXV, 0);
    for (int d = 1; d < MAXV; d++)
        for (int mult = d; mult < MAXV; mult += d)
            cnt[d] += freq[mult];

    // C(m, 2) = m*(m-1)/2 — pairs with gcd divisible by d
    auto pairs = [](long long m) { return m * (m-1) / 2; };

    // g[d] = pairs with gcd EXACTLY d
    // g[d] = pairs(cnt[d]) - sum of g[d*k] for k=2,3,...
    vector<long long> g(MAXV, 0);
    // Process from largest d downward
    for (int d = MAXV - 1; d >= 1; d--) {
        g[d] = pairs(cnt[d]);
        for (int mult = 2 * d; mult < MAXV; mult += d)
            g[d] -= g[mult];
    }

    cout << g[K] << "\n";
    return 0;
}
